@article{ragan-kelleyHalideLanguageCompiler,
 title = {Halide: {{A Language}} and {{Compiler}} for {{Optimizing Parallelism}}, {{Locality}}, and {{Recomputation}} in {{Image Processing Pipelines}}},
 author = {{Ragan-Kelley}, Jonathan and Barnes, Connelly and Adams, Andrew},
 file = {/home/kellen/Downloads/papers/Halide A Language and Compiler for Optimizing Parallelism, Locality, and Recomputation in Image Pro - Ragan-Kelley et al..pdf},
 langid = {english},
 abstract = {Image processing pipelines combine the challenges of stencil computations and stream programs. They are composed of large graphs of different stencil stages, as well as complex reductions, and stages with global or data-dependent access patterns. Because of their complex structure, the performance difference between a naive implementation of a pipeline and an optimized one is often an order of magnitude. Efficient implementations require optimization of both parallelism and locality, but due to the nature of stencils, there is a fundamental tension between parallelism, locality, and introducing redundant recomputation of shared values.}
}

@article{chenNeuralOrdinaryDifferential,
 title = {Neural {{Ordinary Differential Equations}}},
 author = {Chen, Tian Qi and Rubanova, Yulia and Bettencourt, Jesse and Duvenaud, David K},
 file = {/home/kellen/Downloads/papers/Neural Ordinary Differential Equations - Chen et al..pdf},
 langid = {english},
 abstract = {We introduce a new family of deep neural network models. Instead of specifying a discrete sequence of hidden layers, we parameterize the derivative of the hidden state using a neural network. The output of the network is computed using a blackbox differential equation solver. These continuous-depth models have constant memory cost, adapt their evaluation strategy to each input, and can explicitly trade numerical precision for speed. We demonstrate these properties in continuous-depth residual networks and continuous-time latent variable models. We also construct continuous normalizing flows, a generative model that can train by maximum likelihood, without partitioning or ordering the data dimensions. For training, we show how to scalably backpropagate through any ODE solver, without access to its internal operations. This allows end-to-end training of ODEs within larger models.}
}

